import{_ as a,p as n,q as s,a1 as e}from"./framework-5866ffd3.js";const i={},t=e(`<h1 id="uniq" tabindex="-1"><a class="header-anchor" href="#uniq" aria-hidden="true">#</a> uniq</h1><p>显示或忽略重复的行。</p><h2 id="概要" tabindex="-1"><a class="header-anchor" href="#概要" aria-hidden="true">#</a> 概要</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">uniq</span> <span class="token punctuation">[</span>OPTION<span class="token punctuation">]</span><span class="token punctuation">..</span>. <span class="token punctuation">[</span>INPUT <span class="token punctuation">[</span>OUTPUT<span class="token punctuation">]</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="主要用途" tabindex="-1"><a class="header-anchor" href="#主要用途" aria-hidden="true">#</a> 主要用途</h2><ul><li>将输入文件（或标准输入）中邻近的重复行写入到输出文件（或标准输出）中。</li><li>当没有选项时，邻近的重复行将合并为一个。</li></ul><h2 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-c, <span class="token parameter variable">--count</span>                在每行开头增加重复次数。
-d, <span class="token parameter variable">--repeated</span>             所有邻近的重复行只被打印一次。
<span class="token parameter variable">-D</span>                         所有邻近的重复行将全部打印。
--all-repeated<span class="token punctuation">[</span><span class="token operator">=</span>METHOD<span class="token punctuation">]</span>    类似于 -D，但允许每组之间以空行分割。METHOD取值范围<span class="token punctuation">{</span>none<span class="token punctuation">(</span>默认<span class="token punctuation">)</span>，prepend，separate<span class="token punctuation">}</span>。
-f, --skip-fields<span class="token operator">=</span>N        跳过对前N个列的比较。
--group<span class="token punctuation">[</span><span class="token operator">=</span>METHOD<span class="token punctuation">]</span>           显示所有行，允许每组之间以空行分割。METHOD取值范围：<span class="token punctuation">{</span>separate<span class="token punctuation">(</span>默认<span class="token punctuation">)</span>，prepend，append，both<span class="token punctuation">}</span>。
-i, --ignore-case          忽略大小写的差异。
-s, --skip-chars<span class="token operator">=</span>N         跳过对前N个字符的比较。
-u, <span class="token parameter variable">--unique</span>               只打印非邻近的重复行。
-z, --zero-terminated      设置行终止符为NUL（空），而不是换行符。
-w, --check-chars<span class="token operator">=</span>N        只对每行前N个字符进行比较。
<span class="token parameter variable">--help</span>                     显示帮助信息并退出。
<span class="token parameter variable">--version</span>                  显示版本信息并退出。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><p>INPUT（可选）：输入文件，不提供时为标准输入。</p><p>OUTPUT（可选）：输出文件，不提供时为标准输出。</p><h2 id="返回值" tabindex="-1"><a class="header-anchor" href="#返回值" aria-hidden="true">#</a> 返回值</h2><p>返回0表示成功，返回非0值表示失败。</p><h2 id="例子" tabindex="-1"><a class="header-anchor" href="#例子" aria-hidden="true">#</a> 例子</h2><p>注意：命令2和命令3结果一样，命令1仅作了相邻行的去重。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">uniq</span> file.txt
<span class="token function">sort</span> file.txt <span class="token operator">|</span> <span class="token function">uniq</span>
<span class="token function">sort</span> <span class="token parameter variable">-u</span> file.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>只显示单一行，区别在于是否执行排序：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">uniq</span> <span class="token parameter variable">-u</span> file.txt
<span class="token function">sort</span> file.txt <span class="token operator">|</span> <span class="token function">uniq</span> <span class="token parameter variable">-u</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>统计各行在文件中出现的次数：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sort</span> file.txt <span class="token operator">|</span> <span class="token function">uniq</span> <span class="token parameter variable">-c</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在文件中找出重复的行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sort</span> file.txt <span class="token operator">|</span> <span class="token function">uniq</span> <span class="token parameter variable">-d</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="注意" tabindex="-1"><a class="header-anchor" href="#注意" aria-hidden="true">#</a> 注意</h3><ol><li><p><code>uniq</code>只检测邻近的行是否重复，<code>sort -u</code>将输入文件先排序然后再处理重复行。</p></li><li><p>该命令是<code>GNU coreutils</code>包中的命令，相关的帮助信息请查看<code>man -s 1 uniq</code>，<code>info coreutils &#39;uniq invocation&#39;</code>。</p></li></ol>`,24),p=[t];function l(c,r){return n(),s("div",null,p)}const d=a(i,[["render",l],["__file","uniq.html.vue"]]);export{d as default};
